sql:
SELECT COUNT(track_id) 
FROM tracks 
WHERE track_genre = 'Pop' AND explicit = 1;

SELECT user_id, COUNT(*) as total_rated_tracks
FROM track_ratings
GROUP BY user_id;

SELECT track_id, COUNT(*) AS comment_count
FROM track_comments
GROUP BY track_id;

external_knowledge:
- "Stars with fiery hearts" refers to artists;
- "Unleashed the most songs with cautionary labels" refers to artists who released a high number of explicit tracks;
- "Restricted to the top 10 blazing performers" means limiting the output to the top 10 results;
- "2022" refers to the specific year;
- "Songs with cautionary labels" refers to explicit tracks.

- 'popularity scores' refers to the track ratings;
- 'musical pieces' corresponds to the tracks;
- 'most highly regarded' means those with higher average ratings;
- 'prolific' implies artists with a larger number of tracks.

sql:
SELECT t.track_name, a.artist_name, t.mood
FROM tracks t
INNER JOIN artists a ON t.artist_id = a.artist_id;

external_knowledge:
- 'dozen times' refers to 12 plays;
- 'more often' implies a descending order of total play counts;
- 'artists have been listened to' is synonymous with having a higher total play count.

sql:
SELECT artist_name, popularity
FROM artists
ORDER BY popularity DESC;

SELECT track_id, COUNT(DISTINCT user_id) AS commenter_count
FROM track_comments
GROUP BY track_id;

SELECT AVG(strftime('%Y', 'now') - strftime('%Y', T1.birth_date)) AS average_age
FROM users AS T1
JOIN track_ratings AS T2 ON T1.user_id = T2.user_id;

SELECT 
  (SELECT COUNT(*) FROM tracks) AS total_songs, 
  (SELECT COUNT(*) FROM artists) AS total_performers;
